import React, { useState, useRef, useEffect } from 'react';
import MessageBubble from './MessageBubble';
import './ChatWindow.css';

function ChatWindow() {
  const [messages, setMessages] = useState([
    { sender: 'bot', text: 'Hello 👋 I am your AI assistant. How can I help you today?' },
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  // Generate timestamp
  const getTimestamp = () => {
    const now = new Date();
    return now.toLocaleString(); // date + time
  };

  return (
    <div className="chat-window">
      <div className="messages">
        {/* System message */}
        <div className="system-message">
          <p>Connecting to Agent ...</p>
          <span className="timestamp">{getTimestamp()}</span>
        </div>

        {messages.map((msg, i) => (
          <MessageBubble key={i} text={msg.text} sender={msg.sender} />
        ))}

        {isTyping && (
          <div className="message-row bot">
            <div className="avatar">🤖</div>
            <div className="typing-bubble">
              <span></span><span></span><span></span>
            </div>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      <div className="input-area">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Ask something..."
        />
        <button onClick={() => {/* send logic */}}>Send</button>
      </div>
    </div>
  );
}

export default ChatWindow;
